test('el usuario puede crear y completar una tarea', async () => {
  await login('testuser@example.com', 'password');
  await clickButton('Nueva Tarea');
  await fillInput('Titulo de tarea', 'Comprar leche');
  await clickButton('Guardar');

  expect(await getText('.task-list')).toContain('Comprar leche');

  await clickCheckbox('Comprar leche');
  expect(await getText('.completed-tasks')).toContain('Comprar leche');
});
